       font-size: var(--font-size-sm);
       color: var(--color-fg-muted);
     }

     /* Site header */
     .site-header {
       display: flex;
       align-items: center;
       justify-content: space-between;
       padding-block: var(--space-md);
     }
     .site-header__brand {
