       color: var(--color-fg);
       text-decoration: none;
     }
     .site-header__actions {
       display: flex;
       align-items: center;
       gap: var(--space-md);
       font-size: var(--font-size-sm);
       color: var(--color-fg-muted);
     }
     .button--text {
       background: none;
       color: var(--color-fg-muted);
       font-size: var(--font-size-sm);
       font-weight: var(--font-normal);
       padding: 0;
       border-radius: 0;
     }
     .button--text:hover {
       background: none;
       color: var(--color-fg);
       text-decoration: underline;
