     1→use askama::Template;
     2→use axum::extract::State;
     3→use axum::http::StatusCode;
     4→use axum::response::{Html, IntoResponse, Redirect, Response};
     5→use axum::Form;
     6→use sqlx::PgPool;
     7→
     8→use crate::domain::{EmailValidationError, PasswordError};
     9→use crate::services::registration::{register_user, RegistrationError};
    10→
    11→#[derive(Template)]
    12→#[template(path = "register.html")]
    13→pub struct RegisterTemplate {
    14→    pub general_error: Option<String>,
    15→    pub form_email: String,
    16→    pub email_error: Option<String>,
    17→    pub password_error: Option<String>,
    18→    pub password_confirmation_error: Option<String>,
    19→}
    20→
    21→pub async fn get_register() -> Result<impl IntoResponse, RegisterError> {
    22→    let template = RegisterTemplate {
    23→        general_error: None,
    24→        form_email: String::new(),
    25→        email_error: None,
    26→        password_error: None,
    27→        password_confirmation_error: None,
    28→    };
    29→    Ok(Html(template.render()?))
    30→}
    31→
    32→#[derive(serde::Deserialize)]
    33→pub struct RegisterFormData {
    34→    pub email: String,
    35→    pub password: String,
    36→    pub password_confirmation: String,
    37→}
    38→
    39→pub async fn post_register(
    40→    State(pool): State<PgPool>,
    41→    Form(form): Form<RegisterFormData>,
    42→) -> Result<Response, RegisterError> {
    43→    match register_user(
    44→        &pool,
    45→        form.email.clone(),
    46→        form.password,
    47→        form.password_confirmation,
    48→    )
    49→    .await
    50→    {
    51→        Ok(_user_id) => Ok(Redirect::to("/login").into_response()),
    52→        Err(e) => {
    53→            let mut template = RegisterTemplate {
    54→                general_error: None,
    55→                form_email: form.email,
    56→                email_error: None,
    57→                password_error: None,
    58→                password_confirmation_error: None,
    59→            };
    60→
    61→            match &e {
    62→                RegistrationError::InvalidEmail(email_err) => {
    63→                    template.email_error = Some(user_facing_email_error(email_err));
    64→                }
    65→                RegistrationError::InvalidPassword(pwd_err) => {
    66→                    template.password_error = Some(user_facing_password_error(pwd_err));
    67→                }
    68→                RegistrationError::PasswordMismatch => {
    69→                    template.password_confirmation_error =
    70→                        Some("Passwords do not match".to_string());
    71→                }
    72→                RegistrationError::DuplicateEmail => {
    73→                    template.general_error = Some(
    74→                        "Unable to create account. If you already have an account, try <a href=\"/login\">signing in</a>.".to_string()
    75→                    );
    76→                }
    77→                RegistrationError::Unexpected(err) => {
    78→                    tracing::error!(error = ?err, "Unexpected registration error");
    79→                    template.general_error =
    80→                        Some("Something went wrong. Please try again.".to_string());
    81→                }
    82→            }
    83→
    84→            let body = template.render().map_err(RegisterError::Render)?;
    85→            Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
    86→        }
    87→    }
    88→}
    89→
    90→fn user_facing_email_error(err: &EmailValidationError) -> String {
    91→    match err {
    92→        EmailValidationError::Empty => "Enter your email address".to_string(),
    93→        EmailValidationError::MissingAtSymbol => {
    94→            "Enter a valid email address, like name@example.com".to_string()
    95→        }
    96→        EmailValidationError::TooLong => "That email address is too long".to_string(),
    97→    }
    98→}
    99→
   100→fn user_facing_password_error(err: &PasswordError) -> String {
   101→    match err {
   102→        PasswordError::Empty => "Enter a password".to_string(),
   103→        PasswordError::TooShort => "Your password needs at least 8 characters".to_string(),
   104→        PasswordError::TooLong => "That password is too long".to_string(),
   105→    }
   106→}
   107→
   108→#[derive(Debug, thiserror::Error)]
   109→pub enum RegisterError {
   110→    #[error("Failed to render template")]
   111→    Render(#[from] askama::Error),
   112→}
   113→
   114→impl IntoResponse for RegisterError {
   115→    fn into_response(self) -> Response {
   116→        tracing::error!(error = %self, "Registration template rendering failed");
   117→        (
