     1→use askama::Template;
     2→use axum::extract::State;
     3→use axum::http::StatusCode;
     4→use axum::response::{Html, IntoResponse, Redirect, Response};
     5→use axum::Form;
     6→use sqlx::PgPool;
     7→use tower_sessions::Session;
     8→
     9→use crate::services::authentication::{authenticate_user, AuthenticationError};
    10→
    11→#[derive(Template)]
    12→#[template(path = "login.html")]
    13→pub struct LoginTemplate {
    14→    pub error_message: Option<String>,
    15→    pub form_email: String,
    16→}
    17→
    18→pub async fn get_login() -> Result<impl IntoResponse, LoginError> {
    19→    let template = LoginTemplate {
    20→        error_message: None,
    21→        form_email: String::new(),
    22→    };
    23→    Ok(Html(template.render()?))
    24→}
    25→
    26→#[derive(serde::Deserialize)]
    27→pub struct LoginFormData {
    28→    pub email: String,
    29→    pub password: String,
    30→}
    31→
    32→pub async fn post_login(
    33→    State(pool): State<PgPool>,
    34→    session: Session,
    35→    Form(form): Form<LoginFormData>,
    36→) -> Result<Response, LoginError> {
    37→    match authenticate_user(&pool, form.email.clone(), form.password).await {
    38→        Ok(user_id) => {
    39→            session.cycle_id().await.map_err(|e| {
    40→                LoginError::Session(anyhow::anyhow!("Failed to cycle session: {e}"))
    41→            })?;
    42→            session
    43→                .insert("user_id", user_id.as_uuid().to_string())
    44→                .await
    45→                .map_err(|e| {
    46→                    LoginError::Session(anyhow::anyhow!("Failed to store user_id in session: {e}"))
    47→                })?;
    48→            Ok(Redirect::to("/todos").into_response())
    49→        }
    50→        Err(AuthenticationError::InvalidCredentials) => {
    51→            let template = LoginTemplate {
    52→                error_message: Some(
    53→                    "That email or password didn't work. Try again.".to_string(),
    54→                ),
    55→                form_email: form.email,
    56→            };
    57→            let body = template.render().map_err(LoginError::Render)?;
    58→            Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
    59→        }
    60→        Err(AuthenticationError::Unexpected(err)) => {
    61→            tracing::error!(error = ?err, "Unexpected authentication error");
    62→            let template = LoginTemplate {
    63→                error_message: Some("Something went wrong. Please try again.".to_string()),
    64→                form_email: form.email,
    65→            };
    66→            let body = template.render().map_err(LoginError::Render)?;
    67→            Ok((StatusCode::INTERNAL_SERVER_ERROR, Html(body)).into_response())
    68→        }
    69→    }
    70→}
    71→
